            if val.ndim == 1:
                s += "\n  %s(%d)" % (attr, val.shape[0])
            elif 'transformation' in attr:
                s += "\n  %s(in_features=%d, out_features=%d)" % (attr, val.shape[0], val.shape[1])
            else:
                s += "\n  %s(in_features=%d, out_features=%d)" % (attr, val.shape[1], val.shape[0])
        s += "\n)"
        return s

